import math

def calcular_energia_liberada(massa, velocidade):
    """
    Calcula a energia liberada ao impacto do asteroide.
    
    Args:
        massa (float): Massa do asteroide em kg.
        velocidade (float): Velocidade do asteroide em m/s.
    
    Returns:
        float: Energia liberada em joules.
    """
    energia = 0.5 * massa * velocidade ** 2
    return energia

